// DBII-FRAGENDATENBANK — Datenbanken II (Prof. Behrend, TH Köln)
// Grundlage: Vorlesungsfolien VL 1–12, Sommersemester 2026.
// ans ist entweder ein Index oder ein Array für Mehrfachantworten.

// ── BLOCK 1: Erweitertes ERM (VL 1–2) ──
const DBII_B1 = [
  {cat:"Schlüssel",q:"Was kennzeichnet einen Primärschlüssel im ERM?",code:null,opts:["Eine minimale Menge von Attributen, die eine Entität eindeutig identifiziert","Eine beliebige Menge optionaler Attribute","Ein Attribut, das nur in anderen Entity-Mengen vorkommt","Ein Attribut, das mehrfach pro Entity-Typ existieren darf"],ans:0,exp:"Ein Primärschlüssel ist eine minimale Attributmenge zur eindeutigen Identifikation. Alle Schlüsselattribute sind obligatorisch, und pro Entity-Typ gibt es genau einen Primärschlüssel.",source:"VL 1"},
  {cat:"Schlüssel",q:"Welche Aussagen über Zweitschlüssel (Alternative Keys) sind korrekt?",code:null,opts:["Sie können eine Entität eindeutig identifizieren, müssen es aber nicht","Je Entity-Menge kann es beliebig viele Zweitschlüsselmengen geben","NULL-Werte sind bei Zweitschlüsselattributen möglich","Pro Entity-Typ ist maximal ein Zweitschlüssel erlaubt"],ans:[0,1,2],exp:"Zweitschlüssel können eindeutig sein (z.B. Matrikelnummer) oder nicht (z.B. Nachname+Vorname zur Performance-Verbesserung). NULLs sind möglich und es kann beliebig viele geben.",source:"VL 1"},
  {cat:"Schlüssel",q:"Was ist ein Fremdschlüssel?",code:null,opts:["Eine Attributmenge, die in einer anderen Entity-Menge Primärschlüssel ist","Ein Schlüssel, der nur aus künstlichen Attributen besteht","Ein Attribut ohne jede Bedeutung in der realen Welt","Der zweite Schlüssel einer Entity-Menge"],ans:0,exp:"Ein Fremdschlüssel (FK) ist eine Attributmenge, die in einer anderen Entity-Menge Primärschlüssel ist. 1:n/1:cn-Beziehungen werden über Fremdschlüssel implementiert.",source:"VL 1"},
  {cat:"Schlüssel",q:"Welche Vorteile bieten künstliche Schlüssel (surrogate keys)?",code:null,opts:["Weniger Attribute bei Verwendung als Fremdschlüssel","Einfacherer Index-Aufbau und schnellere Suche","Sie ersetzen ggf. zusammengesetzte Primärschlüssel","Sie haben eine direkte Bedeutung in der realen Welt"],ans:[0,1,2],exp:"Surrogate Keys sind zusätzliche Attribute ohne reale Anwendung (i.d.R. NUMBER). Sie machen Fremdschlüssel schlanker, vereinfachen Indexe und beschleunigen die Suche. Die bisherigen Schlüsselattribute werden zu Zweitschlüsseln.",source:"VL 1"},
  {cat:"Beziehungstypen",q:"Was bedeutet die Kardinalität 'c' in den 10 Beziehungsgrundtypen?",code:null,opts:["Genau eine Beziehung","Keine oder eine Beziehung (kann)","Eine oder mehrere Beziehungen","Keine, eine oder mehrere Beziehungen"],ans:1,exp:"c steht für 'kann': keine oder genau eine Beziehung. 1 = genau eine, n = eine oder mehrere, cn = keine, eine oder mehrere.",source:"VL 1"},
  {cat:"Beziehungstypen",q:"Warum muss bei einer m:n-Beziehung im relationalen Schema eine Verknüpfungstabelle angelegt werden?",code:null,opts:["Weil es keinen funktionalen Zusammenhang gibt und keine Fremdschlüssel in den Entity-Typen stehen können","Weil m:n-Beziehungen keine Attribute haben dürfen","Weil das relationale Modell keine Beziehungen kennt","Weil sonst der Primärschlüssel gelöscht werden müsste"],ans:0,exp:"Bei m:n gibt es keinen funktionalen Zusammenhang, deshalb kann kein Fremdschlüssel in einem der beiden Entity-Typen stehen — es braucht eine eigene Zuordnungstabelle.",source:"VL 1"},
  {cat:"Beziehungstypen",q:"Wie werden Beziehungen mit eigenen Attributen (z.B. eine Ehe mit 'von' und 'bis') im ERM realisiert?",code:null,opts:["Über einen eigenen Entity-Typ","Durch Kommentare im Diagramm","Durch mehrwertige Attribute im Supertyp","Gar nicht — Beziehungen können keine Attribute haben"],ans:0,exp:"Sind für Beziehungen eigene Attribute vorgesehen, werden diese über einen eigenen Entity-Typ realisiert (z.B. Entity 'Ehe' mit MannName (FK), FrauName (FK), von, bis).",source:"VL 1"},
  {cat:"Beziehungstypen",q:"Wie wird eine ternäre Beziehung (Grad 3) im ER-Diagramm dargestellt?",code:null,opts:["Als zusätzliche Entity-Menge","Durch drei getrennte 1:1-Beziehungen","Durch eine Raute mit drei Ecken","Ternäre Beziehungen sind nicht modellierbar"],ans:0,exp:"Bei ternären Beziehungen gehen drei Entity-Mengen eine Beziehung ein. Im ER-Diagramm können diese nur als zusätzliche Entity-Menge (z.B. LIEFERT_AN) dargestellt werden.",source:"VL 1"},
  {cat:"Beziehungstypen",q:"Was kennzeichnet eine identifizierende Beziehung?",code:null,opts:["Die Primärschlüsselattribute der Master-Entity-Menge sind auch Primärschlüsselattribute der Detail-Entity-Menge","Die Primärschlüsselattribute der Master treten nur als Fremdschlüssel bei der Detail-Menge auf","Beide Entity-Mengen sind völlig unabhängig voneinander","Sie ist nur bei m:n-Beziehungen möglich"],ans:0,exp:"Bei einer identifizierenden Beziehung treten die PK-Attribute der Master-Entity-Menge auch als identifizierende Attribute (PK) bei der Detail-Entity-Menge auf. Bei nicht-identifizierenden nur als FK.",source:"VL 1"},
  {cat:"Beziehungstypen",q:"Warum können mit surrogate keys (außer bei n:m) keine identifizierenden Beziehungen modelliert werden?",code:null,opts:["Ein künstlicher PK besteht nur aus einem Attribut, eine identifizierende Beziehung erzeugt aber einen mehrattributigen PK","Surrogate Keys dürfen nie als Fremdschlüssel verwendet werden","Identifizierende Beziehungen sind generell verboten","Weil surrogate keys immer NULL sein können"],ans:0,exp:"Ein künstlicher Primärschlüssel besteht nur aus einem Attribut. Eine identifizierende Beziehung erzeugt bei 1:n, 1:cn, 1:c und 1:1 aber einen mehrattributigen Primärschlüssel — Widerspruch.",source:"VL 1"},
  {cat:"IS-A & Vererbung",q:"Welche Aussagen über IS-A-Beziehungen sind korrekt?",code:null,opts:["Supertyp und Subtyp besitzen den gleichen Primärschlüssel","Die Subtypen erben alle Attribute des Supertyps","Subtypen können eigene Attribute ergänzen","Der Subtyp bekommt automatisch einen neuen, eigenen Primärschlüssel"],ans:[0,1,2],exp:"Bei IS-A-Beziehungen teilen Super- und Subtyp den gleichen Primärschlüssel, Subtypen erben alle Attribute und können eigene ergänzen.",source:"VL 1"},
  {cat:"IS-A & Vererbung",q:"Was versteht man unter Generalisierung?",code:null,opts:["Die Gewinnung eines Supertyps aus mehreren ähnlichen Subtypen über gemeinsame Attribute","Die Gewinnung von Subtypen aus einem gegebenen Supertyp","Das Löschen aller Subtypen","Die Zusammenfassung aller Attribute in einer Universaltabelle"],ans:0,exp:"Generalisierung: Aus ähnlichen Subtypen (z.B. Kunden, Angestellte, Lieferanten) wird über gemeinsame Attribute ein Supertyp (z.B. Personen) gebildet. Spezialisierung ist der umgekehrte Prozess.",source:"VL 1"},
  {cat:"IS-A & Vererbung",q:"Ein System von Sub-/Supertypen heißt 'vollständig', wenn …",code:null,opts:["jede Entität zu einem der Subtypen gehört und der Supertyp keine eigenen Entitäten bildet","keine Entität gleichzeitig zu mehreren Subtypen gehört","alle Attribute in allen Subtypen vorkommen","der Supertyp keine Attribute besitzt"],ans:0,exp:"Vollständig: Vom Supertyp lassen sich keine eigenen Entitäten bilden — jede Entität gehört zu einem Subtyp. 'Disjunkt' bedeutet dagegen: keine Entität gehört zu mehreren Subtypen gleichzeitig.",source:"VL 1"},
  {cat:"EERM-Konzepte",q:"Welche Eigenschaften haben existenzabhängige, schwache Entity-Mengen?",code:null,opts:["Ihre Existenz hängt von der Master-Entity-Menge ab","Ihr Primärschlüssel enthält den Primärschlüssel der übergeordneten Entity-Menge als Teilschlüssel","Die Beziehung zur Master-Entity-Menge ist immer identifizierend","Jede identifizierende Beziehung erzeugt automatisch eine schwache Entity-Menge"],ans:[0,1,2],exp:"Schwache Entity-Mengen (z.B. Räume in Gebäuden) sind existenzabhängig, ihr PK enthält den Master-PK als Teilschlüssel und die Beziehung ist immer identifizierend. Umgekehrt gilt das aber nicht: identifizierende Beziehung ≠ schwacher Entity-Typ.",source:"VL 2"},
  {cat:"EERM-Konzepte",q:"Welche Restriktionen hat das klassische ER-Modell?",code:null,opts:["Keine Definition eigener Datentypen","Keine Hierarchien (Subtypen/Vererbung)","Keine Kapselung von Methoden und Attributen","Keine Darstellung von 1:n-Beziehungen"],ans:[0,1,2],exp:"Das klassische ERM kennt keine eigenen Datentypen, keine mehrwertigen/zusammengesetzten Attribute, keine Hierarchien/Vererbung, keine Kapselung und keine temporale Modellierung. 1:n-Beziehungen kann es natürlich darstellen.",source:"VL 1"},
  {cat:"Relationale Abbildung",q:"Wie kann eine 1:1-Beziehung im relationalen Schema korrekt umgesetzt werden?",code:null,opts:["Beide Entity-Mengen zu einer Relation zusammenführen","Zwei Relationen mit Fremdschlüssel plus UNIQUE-Constraint","Nur über eine dritte Zuordnungstabelle","Fremdschlüssel allein reicht immer aus"],ans:[0,1],exp:"Zwei Möglichkeiten: alle Attribute in einer Relation zusammenführen, oder zwei Relationen mit FK. Achtung: Fremdschlüssel realisieren nur 1:n — für 1:1 braucht es zusätzlich ein UNIQUE-Constraint.",source:"VL 2"},
  {cat:"Relationale Abbildung",q:"Was ist der Hauptnachteil der Universaltabelle bei der Abbildung von IS-A-Hierarchien?",code:null,opts:["Potenziell viele NULL-Werte","Es sind keine Anfragen mehr möglich","Vererbung wird doppelt gespeichert","Der Primärschlüssel geht verloren"],ans:0,exp:"Die Universaltabelle fasst alle Attribute aller beteiligten Entity-Typen zusammen — Attribute, die für eine Instanz nicht relevant sind, bleiben NULL. Alternativen: Simulation (Redundanz/Joins) oder objektrelationale Erweiterungen.",source:"VL 2"},
];

// ── BLOCK 2: Objektrelationale Erweiterungen (VL 3–4) ──
const DBII_B2 = [
  {cat:"SQL:1999",q:"Was beschreibt der 'Impedance Mismatch'?",code:null,opts:["Die konzeptionelle Kluft zwischen OO-Programmierung (Objekte, Methoden, Vererbung) und relationalen Datenbanken (Tabellen, atomare Attribute)","Einen Hardwarefehler im Datenbankserver","Die Inkompatibilität zweier SQL-Dialekte","Zu langsame Netzwerkverbindungen zwischen Client und Server"],ans:0,exp:"OO-Sprachen bieten Objekte, Kapselung, benutzerdefinierte Typen, Referenzen und Vererbung — klassisches SQL-92 nur Tabellen mit atomaren Attributen und mengenorientiertem Zugriff. Diese Kluft heißt Impedance Mismatch.",source:"VL 3"},
  {cat:"SQL:1999",q:"Welche Aussagen zu BLOB/CLOB (Large Objects) sind korrekt?",code:null,opts:["BLOB steht für Binary, CLOB für Character Large Object","Operationen wie SUBSTRING, POSITION und LIKE sind erlaubt","LOB-Attribute dürfen nicht Teil eines Schlüssels sein","LOB-Attribute sind bei GROUP BY und ORDER BY erlaubt"],ans:[0,1,2],exp:"BLOB/CLOB speichern große Binär-/Zeichendaten. Erlaubt sind u.a. SUBSTRING, OVERLAY, ||, LIKE, POSITION, LENGTH. Nicht erlaubt: als Schlüsselteil sowie bei GROUP BY, ORDER BY und Größenvergleichen.",source:"VL 3"},
  {cat:"ROW & ARRAY",q:"Was liefert dieser Vergleich?",code:"ROW(1, 2, 7) = ROW(1, NULL, 7)",opts:["TRUE","FALSE","UNKNOWN","Einen Syntaxfehler"],ans:2,exp:"Enthält ein Tupelvergleich NULL an einer entscheidenden Position, ist das Ergebnis UNKNOWN (dreiwertige Logik).",source:"VL 3"},
  {cat:"ROW & ARRAY",q:"Wie greift man auf ein Feld eines ROW-Attributs 'Anschrift' zu?",code:"SELECT Name, ________\nFROM MitarbeiterTupeltabelle;",opts:["Anschrift->Ort","Anschrift.Ort","Anschrift[Ort]","GET(Anschrift, 'Ort')"],ans:1,exp:"Auf Tupelfelder wird mit Punktnotation zugegriffen: Anschrift.Ort. Der Pfeil-Operator -> gilt für Referenzen (REF).",source:"VL 3"},
  {cat:"ROW & ARRAY",q:"Welche Funktion liefert die Anzahl der Elemente eines Arrays?",code:"________(ARRAY['Deutsch','Türkisch'])\n-- liefert 2",opts:["COUNT","LENGTH","SIZE","CARDINALITY"],ans:3,exp:"CARDINALITY(array) liefert die Anzahl der Arrayelemente. UNNEST entschachtelt ein Array in Zeilen, || konkateniert Arrays.",source:"VL 3"},
  {cat:"ROW & ARRAY",q:"Wozu dient UNNEST bei Arraytypen?",code:"SELECT s\nFROM MitarbeiterTupeltabelle,\n     UNNEST(Sprachkenntnisse) s;",opts:["Es entschachtelt ein Array deklarativ in einzelne Zeilen","Es sortiert das Array aufsteigend","Es löscht NULL-Werte aus dem Array","Es wandelt das Array in einen String um"],ans:0,exp:"UNNEST macht aus einem Arraywert eine Zeilenmenge — so kann deklarativ auf einzelne Elemente zugegriffen werden.",source:"VL 3"},
  {cat:"UDTs",q:"Was ist ein Distinct Type?",code:"CREATE TYPE wochenstunden AS INTEGER FINAL;",opts:["Die Umbenennung eines SQL-Basisdatentyps für höhere Typsicherheit","Ein Typ mit mehreren Attributen und Methoden","Eine Tabelle mit eindeutigen Werten","Ein automatisch generierter Objektidentifikator"],ans:0,exp:"Distinct Types benennen einen Basisdatentyp um und verhindern die 'Vermischung' nicht vergleichbarer Werte (z.B. wochenstunden vs. semesterzahl). Ein Vergleich erfordert dann explizite CASTs. Distinct Types sind implizit FINAL.",source:"VL 3"},
  {cat:"UDTs",q:"Welche Aussagen über Structured Types sind korrekt?",code:null,opts:["Sie besitzen benannte Attribute und können Methoden haben","Es gibt nur einfache Vererbung (ein Supertyp)","FINAL-Typen dürfen keine Subtypen haben","Attribute von Structured Types können Constraints wie CHECK besitzen"],ans:[0,1,2],exp:"Structured Types haben Attribute und Methoden, unterstützen nur einfache Vererbung (UNDER) und FINAL verbietet Subtypen. Constraints sind bei den Attributen NICHT möglich.",source:"VL 3"},
  {cat:"UDTs",q:"Was sind Observer- und Mutator-Methoden?",code:null,opts:["Automatisch erzeugte Methoden zum Lesen bzw. Ändern von Attributen eines UDT","Manuell zu programmierende Trigger","Spezielle Aggregatfunktionen","Methoden zur Indexverwaltung"],ans:0,exp:"Observer (lesen, z.B. hiwi.name()) und Mutatoren (ändern, z.B. hiwi.stunden(15)) werden bei der Typdefinition automatisch erzeugt. Kurzform beim Mutator: SET hiwi.stunden = 15.",source:"VL 3"},
  {cat:"UDTs",q:"Wie wird eine neue Instanz eines Structured Type im SQL-Standard erzeugt?",code:"SET hiwi = ________ hilfskraft('Helge Schneider','III',7);",opts:["CREATE","NEW","INIT","MAKE"],ans:1,exp:"SQL erlaubt keinen direkten Konstruktoraufruf — der NEW-Operator ruft die Initialisierungsmethode auf und führt implizit den Konstruktor aus.",source:"VL 3"},
  {cat:"UDTs",q:"Mit welchem Schlüsselwort erbt ein Structured Type von einem Supertyp?",code:"CREATE TYPE hilfskraft ________ mitarbeiter\nAS (stunden INT) NOT FINAL;",opts:["EXTENDS","INHERITS","UNDER","SUBTYPE OF"],ans:2,exp:"Vererbung bei Structured Types erfolgt mit UNDER: der Subtyp erbt Struktur (Attribute) und Verhalten (Methoden). INHERITS ist die PostgreSQL-Variante für Tabellen.",source:"VL 3"},
  {cat:"Typed Tables & REF",q:"Was kennzeichnet eine typisierte Tabelle?",code:"CREATE TABLE hilfskraft_tbl OF hilfskraft ...",opts:["Sie speichert Objekte eines strukturierten Typs und besitzt eine self-referencing column (OID)","Sie darf nur Basisdatentypen enthalten","Sie ist eine reine View ohne Speicherung","Ihre Zeilen können nicht referenziert werden"],ans:0,exp:"Typisierte Tabellen (CREATE TABLE ... OF Typ) speichern Objektmengen. Jede Zeile erhält einen Objektidentifikator (OID) in der self-referencing column und ist damit über Referenzspalten referenzierbar.",source:"VL 4"},
  {cat:"Typed Tables & REF",q:"Wozu dient die SCOPE-Klausel bei Referenztypen?",code:"Ehepartner REF(PersonTyp) SCOPE Personen",opts:["Sie bestimmt die typisierte Tabelle, deren Instanzen referenziert werden","Sie beschränkt Zugriffsrechte auf ein Schema","Sie legt die maximale Anzahl an Referenzen fest","Sie aktiviert die automatische Löschweitergabe"],ans:0,exp:"REF(Typ) SCOPE (TypisierteTabelle) legt den Wertebereich fest: Nur Instanzen dieser typisierten Tabelle können referenziert werden, und nur mit Scope ist Dereferenzierung (DEREF) möglich.",source:"VL 4"},
  {cat:"Typed Tables & REF",q:"Wie greift man auf ein Attribut eines referenzierten Objekts zu?",code:null,opts:["Mit dem Pfeil-Operator (Dereferenzierung plus Attributselektion)","Nur über einen expliziten JOIN","Mit doppelter Punktnotation","Gar nicht — Referenzen sind nicht auflösbar"],ans:0,exp:"Der Pfeil-Operator (z.B. Vorgesetzter->Name) entspricht Dereferenzierung plus Attributselektion. Alternativ: DEREF(oid).Attribut bzw. DEREF(oid).Methode(...).",source:"VL 4"},
  {cat:"PostgreSQL",q:"Mit welchem Konstrukt realisiert PostgreSQL Tabellenvererbung?",code:"CREATE TABLE StudentTabelle ( ... )\n________ MitarbeiterTupeltabelle;",opts:["UNDER","INHERITS","EXTENDS","OF TYPE"],ans:1,exp:"PostgreSQL nutzt INHERITS Supertabellenname(n) für die Tabellenvererbung — anders als der SQL-Standard, der UNDER für Typen verwendet.",source:"VL 4"},
];

// ── BLOCK 3: SQL für Data Science (VL 5) ──
const DBII_B3 = [
  {cat:"Window Functions",q:"Was unterscheidet Window Functions von Aggregatfunktionen mit GROUP BY?",code:null,opts:["Bei Window Functions bleiben alle Zeilen erhalten — die Ergebnisse werden nicht zu einer Zeile zusammengezogen","Window Functions können keine Durchschnitte berechnen","GROUP BY liefert immer mehr Zeilen als Window Functions","Es gibt keinen Unterschied"],ans:0,exp:"Aggregatfunktionen bilden pro Gruppe eine Ergebniszeile. Window Functions berechnen pro Input-Zeile eine Resultatszeile und nutzen dafür die Nachbarzeilen (row vicinity → row).",source:"VL 5"},
  {cat:"Window Functions",q:"Was gibt diese Abfrage pro Zeile aus?",code:"SELECT depname, empno, salary,\n  AVG(salary) OVER (PARTITION BY depname)\nFROM empsalary;",opts:["Jede Person mit ihrem Gehalt und dem Durchschnittsgehalt ihrer Abteilung","Nur eine Zeile pro Abteilung mit dem Durchschnitt","Das Durchschnittsgehalt über alle Abteilungen","Einen Fehler, da GROUP BY fehlt"],ans:0,exp:"PARTITION BY depname bildet pro Abteilung eine Partition. Jede Zeile bleibt erhalten und bekommt zusätzlich den Durchschnitt ihrer Partition.",source:"VL 5"},
  {cat:"Window Functions",q:"Was passiert, wenn man bei einer Window Function das PARTITION BY weglässt?",code:"AVG(salary) OVER ()",opts:["Es gibt nur eine Partition mit allen Zeilen — der Durchschnitt wird über alle Werte berechnet","Die Abfrage schlägt fehl","Jede Zeile bildet ihre eigene Partition","Es wird automatisch nach der ersten Spalte partitioniert"],ans:0,exp:"Ohne PARTITION BY existiert genau eine Partition (alle Zeilen). Das Aggregat bezieht sich dann auf die gesamte Tabelle.",source:"VL 5"},
  {cat:"Window Functions",q:"Worin unterscheiden sich rank() und dense_rank()?",code:null,opts:["rank() überspringt nach gleichen Werten Ränge, dense_rank() vergibt lückenlose Ränge","dense_rank() nummeriert jede Zeile eindeutig durch","rank() funktioniert nur ohne ORDER BY","Es gibt keinen Unterschied"],ans:0,exp:"Bei Gleichständen vergibt rank() denselben Rang und überspringt danach (1,1,3), dense_rank() bleibt lückenlos (1,1,2). row_number() nummeriert dagegen jede Zeile eindeutig durch.",source:"VL 5"},
  {cat:"Window Functions",q:"Warum dürfen Window Functions nicht im WHERE, GROUP BY oder HAVING vorkommen?",code:null,opts:["Weil sie (mit Ausnahme von ORDER BY) zu allerletzt evaluiert werden","Weil sie zu langsam für Filterbedingungen sind","Weil der SQL-Standard sie nur im FROM erlaubt","Weil sie keine numerischen Werte liefern"],ans:0,exp:"Window Functions werden erst nach WHERE, GROUP BY und HAVING ausgewertet — nur ORDER BY kommt noch später. Deshalb können ihre Ergebnisse dort nicht referenziert werden.",source:"VL 5"},
  {cat:"Window Functions",q:"Mit welchem SQL-Standard wurden Window Functions eingeführt?",code:null,opts:["SQL-92","SQL:1999","SQL:2003","SQL:2016"],ans:2,exp:"Window Functions kamen mit SQL:2003 als weiterer Modus der zeilenbasierten Berechnung in den ISO-Standard. Oracle nennt sie Analytic Functions.",source:"VL 5"},
  {cat:"Window Functions",q:"Wozu dient die WINDOW-Klausel am Ende einer Abfrage?",code:"SELECT rank() OVER w, dense_rank() OVER w\nFROM empsalary\nWINDOW w AS (PARTITION BY depname\n             ORDER BY salary DESC);",opts:["Sie definiert ein benanntes Window, das mehrfach wiederverwendet werden kann","Sie beschränkt die Ergebnismenge auf ein Zeitfenster","Sie erstellt einen temporären Index","Sie ist ein Alias für GROUP BY"],ans:0,exp:"Mit WINDOW name AS (...) bekommt die Window-Definition einen Namen und kann von mehreren Window Functions per OVER name genutzt werden — das vermeidet Wiederholung.",source:"VL 5"},
  {cat:"Frames",q:"Was ist ein Window Frame?",code:null,opts:["Eine pro Zeile definierte Teilmenge der Partition, die in die Berechnung einbezogen wird","Ein grafisches Element der Datenbankoberfläche","Ein Synonym für die gesamte Tabelle","Der Primärschlüssel einer Partition"],ans:0,exp:"Für jede Zeile gibt es innerhalb ihrer Partition eine Menge von Zeilen — den Window Frame. Viele (aber nicht alle) Window Functions rechnen nur über den Frame statt über die ganze Partition.",source:"VL 5"},
  {cat:"Frames",q:"Welcher Frame berechnet einen gleitenden Drei-Tage-Durchschnitt?",code:"AVG(price) OVER (ORDER BY date\n  ROWS BETWEEN ________ AND CURRENT ROW)",opts:["2 PRECEDING","3 PRECEDING","2 FOLLOWING","UNBOUNDED PRECEDING"],ans:0,exp:"ROWS BETWEEN 2 PRECEDING AND CURRENT ROW umfasst die aktuelle Zeile plus die zwei Vorgänger — also drei Werte für den gleitenden Durchschnitt.",source:"VL 5"},
  {cat:"Anwendung",q:"Wozu dient der gleitende Durchschnitt in der Datenanalyse?",code:null,opts:["Trends erkennen, indem kurzfristige Schwankungen herausgerechnet werden","Die Daten physisch zu sortieren","Duplikate zu entfernen","NULL-Werte zu ersetzen"],ans:0,exp:"Der gleitende Durchschnitt ist eine Zeitreihentechnik: Der Mittelwert aus dem aktuellen und einer Anzahl vorausgehender Werte glättet kurzfristige Schwankungen und macht Trends sichtbar.",source:"VL 5"},
  {cat:"Anwendung",q:"Wie lassen sich mit zwei gleitenden Durchschnitten Trendumkehrungen bestimmen?",code:null,opts:["An den Schnittpunkten von kurzfristigem und langfristigem gleitenden Durchschnitt","Am absoluten Maximum der Kurve","Durch Sortieren nach dem Preis","Durch Löschen der Ausreißer"],ans:0,exp:"Betrachtet man einen kurzfristigen (z.B. 2 Tage) und einen langfristigen (z.B. 30 Tage) gleitenden Durchschnitt, deuten deren Schnittpunkte bei zyklischen Daten auf Trend-Änderungen hin (Achtung: Fehlsignale möglich).",source:"VL 5"},
  {cat:"Anwendung",q:"Welcher Berechnungsmodus gehört zu einer klassischen Aggregatfunktion?",code:null,opts:["row → row","row → table of rows","group of rows → row","row vicinity → row"],ans:2,exp:"Funktionen: row→row. Table-generating functions: row→table of rows. Aggregate: group of rows→row (eine pro Gruppe). Window Functions: row vicinity→row (eine pro Zeile).",source:"VL 5"},
];

// ── BLOCK 4: DB-Anbindung & JDBC (VL 6) ──
const DBII_B4 = [
  {cat:"JDBC-Grundlagen",q:"Welche drei Ansätze zur DB-Anbindung an Programmiersprachen gibt es?",code:null,opts:["Erweiterung der Programmiersprache (z.B. Pascal/R)","Embedded SQL mit Pre-Compiler (z.B. SQLJ)","Call Level Interface über Funktions-API (z.B. ODBC, JDBC)","Direkter Speicherzugriff auf die DB-Dateien"],ans:[0,1,2],exp:"Historisch: Spracherweiterungen. Embedded SQL: markierte SQL-Anweisungen, die ein Pre-Compiler umwandelt. CLI: Aufruf von SQL über eine Funktions-API wie ODBC oder JDBC.",source:"VL 6"},
  {cat:"JDBC-Grundlagen",q:"Wofür wird executeUpdate() verwendet und was liefert es zurück?",code:null,opts:["Für DDL/DML-Befehle; es liefert die Anzahl der betroffenen Tupel (bei DDL immer 0)","Für SELECT-Anweisungen; es liefert ein ResultSet","Nur für Transaktionssteuerung; es liefert einen Boolean","Für Stored Procedures; es liefert die Output-Parameter"],ans:0,exp:"executeUpdate() dient dem Schreibzugriff (DDL/DML) und liefert einen Integer: die Anzahl betroffener Tupel, bei DDL-Befehlen immer 0. SELECTs laufen über executeQuery().",source:"VL 6"},
  {cat:"JDBC-Grundlagen",q:"Wozu dient executeBatch()?",code:null,opts:["Mehrere per addBatch() gesammelte SQL-Befehle gemeinsam abzuschicken","Eine Abfrage in mehreren Threads auszuführen","Das ResultSet in Seiten aufzuteilen","Automatische Wiederholung bei Fehlern"],ans:0,exp:"Mit addBatch() werden mehrere SQL-Befehle gesammelt und mit executeBatch() gemeinsam abgeschickt — das spart Roundtrips zur Datenbank.",source:"VL 6"},
  {cat:"ResultSet",q:"Wie durchläuft man ein ResultSet und greift auf Spalten zu?",code:"ResultSet rs = stmt.executeQuery(\"SELECT ...\");\nwhile ( ________ ) {\n  String s = rs.getString(1);\n  float g = rs.getFloat(\"Gehalt\");\n}",opts:["rs.hasNext()","rs.next()","rs.forward()","!rs.isLast()"],ans:1,exp:"Das ResultSet ist ein Iterator: next() springt zum nächsten Datensatz und liefert false am Ende. Spaltenzugriff erfolgt über typspezifische get-Methoden per Position oder Spaltenname.",source:"VL 6"},
  {cat:"ResultSet",q:"Welches Standardverhalten hat ein ResultSet?",code:null,opts:["Nur sequentielles Durchlaufen vorwärts und nur lesend","Beliebige Navigation und Schreibzugriff","Automatische Sortierung nach dem Primärschlüssel","Zwischenspeicherung aller Zeilen im Client"],ans:0,exp:"Standardmäßig ist ein ResultSet forward-only und read-only. Scrollable/updatable ResultSets müssen explizit beim createStatement() angefordert werden (z.B. TYPE_SCROLL_INSENSITIVE, CONCUR_UPDATABLE).",source:"VL 6"},
  {cat:"ResultSet",q:"Welche Methode springt in einem scrollable ResultSet direkt zur Zeile mit Nummer x?",code:null,opts:["relative(x)","jump(x)","absolute(x)","goto(x)"],ans:2,exp:"absolute(x) springt zur Zeile x, relative(x) bewegt sich um x Zeilen relativ (negativ = rückwärts). Außerdem gibt es first(), last(), previous(), beforeFirst(), afterLast().",source:"VL 6"},
  {cat:"ResultSet",q:"Unter welcher Voraussetzung funktioniert ein updatable ResultSet?",code:null,opts:["Die Query selektiert nur eine Tabelle und von dieser alle Attribute des Primary Key","Die Tabelle darf keinen Primärschlüssel haben","Die Query muss ein GROUP BY enthalten","Es müssen mindestens zwei Tabellen gejoint werden"],ans:0,exp:"Ein updatable ResultSet ist nur möglich, wenn die Query genau eine Tabelle nutzt und alle PK-Attribute dieser Tabelle selektiert. Dann sind updateRow(), deleteRow() und insertRow() möglich.",source:"VL 6"},
  {cat:"ResultSet",q:"Wie erhält man Metadaten (Spaltenanzahl, -namen, -typen) zu einem ResultSet?",code:null,opts:["Über rs.getMetaData() und die Klasse ResultSetMetaData","Über eine zweite SELECT-Anfrage auf das Data Dictionary","Nur über den JDBC-Treiberhersteller","Metadaten sind in JDBC nicht verfügbar"],ans:0,exp:"ResultSetMetaData rsmd = rs.getMetaData() liefert u.a. getColumnCount(), getColumnName(i), getColumnType(i) und die DB-spezifische Typbezeichnung.",source:"VL 6"},
  {cat:"Prepared Statements",q:"Was ist der Hauptvorteil von Prepared Statements?",code:null,opts:["Das DBMS muss Parsen und Anfrageoptimierung nur einmal durchführen","Sie liefern immer sortierte Ergebnisse","Sie umgehen die Zugriffsrechte","Sie benötigen keine Datenbankverbindung"],ans:0,exp:"Ein Prepared Statement definiert das SQL einmal mit bind variables (?). Bei jeder Ausführung werden nur neue Werte per set-Methoden gebunden — Parsen und Optimieren entfällt bei Wiederholungen.",source:"VL 6"},
  {cat:"Prepared Statements",q:"Welche Zeile bindet den Wert korrekt an das Prepared Statement?",code:"PreparedStatement pstmt = conn.prepareStatement(\n  \"SELECT * FROM Studenten WHERE Semester = ?\");\n________\nrs = pstmt.executeQuery();",opts:["pstmt.bind(1, 4);","pstmt.setInt(1, 4);","pstmt.setParameter(\"Semester\", 4);","pstmt.addInt(4);"],ans:1,exp:"Bind variables werden über typspezifische set-Methoden mit ihrer Position gesetzt: pstmt.setInt(1, 4) bindet den ersten Platzhalter.",source:"VL 6"},
  {cat:"SQL Injection",q:"Was bewirkt die Eingabe ' OR 'a'='a bei einem unsicher zusammengebauten Login-Statement?",code:"SELECT ... FROM login\nWHERE user='' OR 'a'='a'\n  AND pass='' OR 'a'='a'",opts:["Die Bedingungsprüfung wird per Tautologie umgangen — der Login gelingt ohne gültige Daten","Die Datenbank wird sofort gelöscht","Nichts, SQL ignoriert solche Eingaben","Es entsteht nur ein Syntaxfehler"],ans:0,exp:"'a'='a' ist immer wahr (Tautologie). Damit wird die WHERE-Bedingung ausgehebelt. Mit '; DROP TABLE login; -- ließe sich sogar eigener Code einschleusen.",source:"VL 6"},
  {cat:"SQL Injection",q:"Warum schützen Prepared Statements (teilweise) vor SQL Injections?",code:null,opts:["Eingaben werden als reine Werte gebunden und nicht als SQL-Teilausdrücke interpretiert","Sie verschlüsseln die komplette Verbindung","Sie prüfen Passwörter automatisch","Sie blockieren alle Sonderzeichen"],ans:0,exp:"Bind variables verhindern, dass Eingaben als SQL-Code (z.B. DROP) interpretiert werden. Achtung laut Vorlesung: Das verhindert nur das Einschleusen von Teilausdrücken — weitere Checks und ggf. Escape-Sequenzen bleiben nötig.",source:"VL 6"},
  {cat:"Prepared Statements",q:"Wofür braucht man Callable Statements?",code:"CallableStatement cs =\n  con.prepareCall(\"{call accountlogin(?,?,?)}\");\ncs.registerOutParameter(3, Types.DATE);",opts:["Für den Aufruf von Stored Procedures mit Output-Parametern","Für einfache SELECT-Anweisungen","Für die Definition neuer Tabellen","Für asynchrone Abfragen"],ans:0,exp:"Callable Statements rufen Stored Procedures/Functions auf. Output-Parameter müssen mit registerOutParameter() registriert und nach dem execute per get-Methoden ausgelesen werden. Die {call ...}-Schreibweise ist JDBC-Escape-Syntax für Portabilität.",source:"VL 6"},
];

// ── BLOCK 5: Transaktionen (VL 7–8) ──
const DBII_B5 = [
  {cat:"Anomalien",q:"Was passiert beim Lost-Update-Problem?",code:null,opts:["Änderungsoperationen einer Transaktion gehen durch Überschreiben verloren","Eine Transaktion liest Daten, die nie committet wurden","Eine Anfrage sieht plötzlich neue Tupel","Die Datenbank stürzt ab"],ans:0,exp:"Beim Lost Update überschreibt eine Transaktion die Änderung einer anderen, weil beide denselben alten Wert gelesen haben — eine Änderung geht verloren.",source:"VL 7"},
  {cat:"Anomalien",q:"Was kennzeichnet das Dirty-Read-Problem?",code:null,opts:["Eine Transaktion liest inkonsistente Daten einer anderen, die später abgebrochen wird","Zwei Transaktionen schreiben gleichzeitig auf verschiedene Objekte","Eine Transaktion liest dieselben Daten zweimal","Der Index wird nicht aktualisiert"],ans:0,exp:"Beim Dirty Read werden 'voreilig' geschriebene, noch nicht committete Daten gelesen. Bricht die schreibende Transaktion ab (abort), hat die lesende mit ungültigen Daten gearbeitet.",source:"VL 7"},
  {cat:"Anomalien",q:"Was ist das Phantom-Problem?",code:"T2: SELECT sum(Kontostand) FROM Konten\nT1: INSERT INTO Konten VALUES (C,1000,...)\nT2: SELECT sum(Kontostand) FROM Konten\n    -- anderes Ergebnis!",opts:["Eine konkurrierende Transaktion bewirkt eine Wertänderung, die aus Sicht der eigenen Transaktion nicht erklärbar ist","Eine Transaktion wird doppelt ausgeführt","Gelöschte Daten bleiben im Puffer sichtbar","Der Serialisierbarkeitsgraph enthält unsichtbare Knoten"],ans:0,exp:"Durch das INSERT von T1 'erscheint' für T2 ein Phantom-Tupel: Die gleiche Anfrage liefert plötzlich ein anderes Ergebnis, ohne dass T2 selbst etwas geändert hat.",source:"VL 7"},
  {cat:"Serialisierbarkeit",q:"Wann heißt eine Menge verzahnt ausgeführter Transaktionen serialisierbar?",code:null,opts:["Wenn ihr Ergebnis genau dem einer der möglichen seriellen Abarbeitungen entspricht","Wenn alle Transaktionen gleichzeitig committen","Wenn keine Transaktion Schreiboperationen enthält","Wenn jede Transaktion höchstens eine Operation hat"],ans:0,exp:"Serialisierbar = die verzahnte Ausführung ist äquivalent zu irgendeiner seriellen Reihenfolge. Welche serielle Reihenfolge simuliert wird, ist für die Isolation egal.",source:"VL 7"},
  {cat:"Serialisierbarkeit",q:"Welche Operationspaare auf demselben Datenobjekt A sind Konfliktoperationen?",code:null,opts:["read(A) / write(A)","write(A) / read(A)","write(A) / write(A)","read(A) / read(A)"],ans:[0,1,2],exp:"Konflikt besteht, wenn beide Operationen dasselbe Objekt betreffen und mindestens eine schreibt. Zwei Leseoperationen stehen nie in Konflikt.",source:"VL 7"},
  {cat:"Serialisierbarkeit",q:"Wie prüft man mit dem Serialisierbarkeitsgraphen SG(H), ob eine Historie serialisierbar ist?",code:null,opts:["H ist serialisierbar genau dann, wenn SG(H) zyklenfrei ist","H ist serialisierbar, wenn SG(H) mindestens einen Zyklus enthält","H ist serialisierbar, wenn SG(H) vollständig verbunden ist","Der Graph sagt nichts über Serialisierbarkeit aus"],ans:0,exp:"Der Serialisierbarkeitsgraph hält Konflikte auf Transaktionsebene fest. Ist er zyklenfrei, ist die Historie serialisierbar — ein Zyklus bedeutet: nicht serialisierbar.",source:"VL 7"},
  {cat:"Serialisierbarkeit",q:"Warum werden lokale Variablen bei der Serialisierbarkeitsanalyse ignoriert?",code:null,opts:["Serialisierbarkeit muss unabhängig von lokalen Zuweisungen und DB-Zuständen gelten — nur Lese- und Schreiboperationen sind relevant","Weil lokale Variablen immer konstant sind","Weil das DBMS lokale Variablen nicht kennt","Weil sie automatisch gesperrt werden"],ans:0,exp:"Dieselben kritischen Operationen können je nach Zwischenrechnungen mal korrekt, mal fehlerhaft wirken. Deshalb konzentriert sich die Serialisierbarkeitstheorie ausschließlich auf die read-/write-Operationen.",source:"VL 7"},
  {cat:"Sperrverfahren",q:"Welche Aussagen über Sperrmodi sind korrekt?",code:null,opts:["Mehrere Transaktionen können gleichzeitig S-Sperren auf dasselbe Objekt halten","Nur eine Transaktion kann zur Zeit eine X-Sperre auf ein Objekt halten","Mit einer S-Sperre darf gelesen werden","Eine X-Sperre erlaubt anderen Transaktionen weiterhin das Lesen"],ans:[0,1,2],exp:"S-Sperren (read locks) sind untereinander verträglich; X-Sperren (exclusive/write locks) sind mit nichts verträglich — weder mit S- noch mit anderen X-Sperren.",source:"VL 7"},
  {cat:"Sperrverfahren",q:"Was fordert das Zwei-Phasen-Sperrprotokoll (2PL)?",code:null,opts:["Jede Transaktion sperrt zunächst alle benötigten Daten (lock phase) und gibt sie danach nur noch frei (unlock phase)","Jede Sperre muss genau zwei Sekunden gehalten werden","Sperren dürfen beliebig angefordert und freigegeben werden","Es dürfen maximal zwei Objekte gesperrt werden"],ans:0,exp:"2PL: Nach der ersten Freigabe darf keine neue Sperre mehr angefordert werden. Bei Einhaltung von 2PL garantiert der Scheduler serialisierbare Historien.",source:"VL 7"},
  {cat:"Optimistische Synchronisation",q:"Aus welchen drei Phasen besteht die optimistische Synchronisation?",code:null,opts:["Lesephase, Validierungsphase, Schreibphase","Sperrphase, Wartephase, Freigabephase","Parse-, Optimierungs-, Ausführungsphase","Undo-, Redo-, Commit-Phase"],ans:0,exp:"1. Lesephase: Operationen auf einer lokalen Kopie. 2. Validierungsphase (atomar): Konfliktprüfung. 3. Schreibphase (atomar): Änderungen positiv validierter Transaktionen persistieren.",source:"VL 8"},
  {cat:"Optimistische Synchronisation",q:"Wann steht Ti beim BOCC-Test im Konflikt mit einer bereits validierten Transaktion Tj?",code:"IF ________ THEN abort Ti\nELSE Schreibphase Ti",opts:["RS(Ti) ∩ WS(Tj) ≠ ∅","WS(Ti) ∩ WS(Ti) = ∅","RS(Ti) ∪ WS(Tj) = ∅","RS(Ti) ⊆ RS(Tj)"],ans:0,exp:"Backward-Oriented Concurrency Control validiert gegen beendete Transaktionen: Schneidet das Read Set von Ti das Write Set einer seit BOT erfolgreich validierten Tj, wird Ti zurückgesetzt.",source:"VL 8"},
  {cat:"Optimistische Synchronisation",q:"Welche Nachteile hat BOCC?",code:null,opts:["Unnötige Rücksetzungen durch ungenaue Konfliktanalyse","Write Sets beendeter Transaktionen müssen aufbewahrt werden","Hohes Rücksetzrisiko für lange Transaktionen und bei Hot Spots","Es können Deadlocks zwischen Sperren entstehen"],ans:[0,1,2],exp:"BOCC setzt teils unnötig zurück (auch wenn bereits die aktuelle Version gelesen wurde), braucht alte Write Sets, viele Vergleiche, und lange TAs sind gefährdet ('Starvation'). Deadlocks gibt es bei optimistischen Verfahren gerade NICHT.",source:"VL 8"},
  {cat:"Optimistische Synchronisation",q:"Welche Aussagen zum Vergleich pessimistischer und optimistischer Synchronisation stimmen?",code:null,opts:["Pessimistisch: Konfliktvermeidung durch Blockieren, reale Gefahr von Verklemmungen","Optimistisch: Konfliktauflösung durch Rücksetzen, keine Verklemmungen","Nahezu alle kommerziellen DBS setzen auf Sperrverfahren","Optimistische Verfahren setzen häufige Konflikte voraus"],ans:[0,1,2],exp:"Pessimistisch nimmt häufige Konflikte an und blockiert (Deadlock-Gefahr, weniger Rücksetzungen). Optimistisch nimmt seltene Konflikte an und setzt zurück (keine Deadlocks). Kommerziell dominieren Sperrverfahren.",source:"VL 8"},
];

// ── BLOCK 6: Trigger & Integrität (VL 9) ──
const DBII_B6 = [
  {cat:"Integritätsbedingungen",q:"Welche Arten von Integritätsbedingungen unterscheidet die Vorlesung?",code:null,opts:["Statische sowie dynamische (transitionale und temporale)","Nur syntaktische und semantische","Interne und externe","Primäre und sekundäre"],ans:0,exp:"Statische IB beschreiben den korrekten Zustand. Dynamische beschreiben Zustandsübergänge: transitional (ein Übergang, :OLD/:NEW) und temporal (Folge von Übergängen, braucht historische Daten).",source:"VL 9"},
  {cat:"Integritätsbedingungen",q:"'Der Rabatt eines ausländischen Kunden darf nicht über 30% liegen.' — Womit ist das am einfachsten umsetzbar?",code:null,opts:["CHECK-Constraint","Nur mit einem AFTER-STATEMENT-Trigger","Mit einer Stored Procedure im Client","Gar nicht in SQL"],ans:0,exp:"Diese statische Bedingung betrifft nur Attributwerte einer Zeile und ist per CHECK lösbar. Bedingungen wie 'Es muss mindestens einen Kunden geben' oder Vergleiche mit anderen Tabellen brauchen dagegen Trigger.",source:"VL 9"},
  {cat:"Integritätsbedingungen",q:"Womit lassen sich transitionale Integritätsbedingungen (z.B. Statuswechsel nur 'bestellt' → 'geliefert') grundsätzlich lösen?",code:null,opts:["Nur mit ROW-Triggern und den Transitionsvariablen :NEW und :OLD","Mit einem einfachen UNIQUE-Constraint","Mit einer DEFAULT-Klausel","Mit einem Index auf der Statusspalte"],ans:0,exp:"Transitionale IB vergleichen alten und neuen Zustand — das geht nur mit ROW-Triggern über die Transitionsvariablen :OLD und :NEW.",source:"VL 9"},
  {cat:"Trigger-Grundlagen",q:"Worin unterscheiden sich ROW- und STATEMENT-Trigger?",code:null,opts:["ROW-Trigger feuern einmal pro manipuliertem Datensatz, STATEMENT-Trigger einmal pro DML-Befehl","STATEMENT-Trigger feuern pro Datensatz, ROW-Trigger pro Befehl","Beide feuern identisch oft","ROW-Trigger existieren nur in NoSQL-Systemen"],ans:0,exp:"Ein UPDATE auf 3 Datensätze lässt einen ROW-Trigger 3× feuern, einen STATEMENT-Trigger nur 1×.",source:"VL 9"},
  {cat:"Trigger-Grundlagen",q:"Warum sind COMMIT und ROLLBACK in normalen DML-Triggern verboten?",code:"CREATE TRIGGER ... FOR EACH ROW\nBEGIN\n  UPDATE Teile SET ...;\n  COMMIT;  -- Fehler!\nEND;",opts:["Trigger sind Bestandteil der auslösenden Transaktion — DML-Befehl und Trigger bilden eine atomare Einheit","Weil COMMIT nur im Client erlaubt ist","Weil Trigger keine Schreibrechte haben","Das ist gar nicht verboten"],ans:0,exp:"DML-Anweisung, Constraints und alle gefeuerten Trigger bilden eine atomare Ausführungseinheit. Schlägt etwas fehl, wird alles zurückgerollt — deshalb darf ein Trigger die Transaktion nicht selbst beenden.",source:"VL 9"},
  {cat:"Trigger-Grundlagen",q:"Wie erlaubt Oracle trotzdem COMMIT innerhalb eines Triggers, z.B. für robuste Protokollierung?",code:"CREATE TRIGGER log_trigger\nBEFORE INSERT ON employees FOR EACH ROW\nDECLARE ________;\nBEGIN\n  INSERT INTO protokoll VALUES (...);\n  COMMIT;\nEND;",opts:["PRAGMA AUTONOMOUS_TRANSACTION","SET COMMIT ALLOWED","ENABLE NESTED COMMIT","PRAGMA FORCE_COMMIT"],ans:0,exp:"Mit PRAGMA AUTONOMOUS_TRANSACTION läuft der Triggerkörper als autonome Transaktion. Das COMMIT betrifft nur diese, nicht die Haupttransaktion — ideal für Protokollierung, die auch bei Fehlversuchen erhalten bleibt.",source:"VL 9"},
  {cat:"Trigger-Grundlagen",q:"Welches Problem kann bei kaskadierenden Triggern auftreten?",code:null,opts:["Ein Terminierungsproblem bei Rekursion, da DML-Befehle im Aktionsteil weitere Trigger feuern können","Sie können nur einmal pro Tag ausgeführt werden","Sie deaktivieren alle Constraints","Sie sperren automatisch die ganze Datenbank"],ans:0,exp:"DML-Befehle im Aktionsteil eines Triggers können ihrerseits Trigger feuern (Kaskadierung). Bei Rekursion droht ein Terminierungsproblem.",source:"VL 9"},
  {cat:"Ausführungsmodelle",q:"Ein UPDATE manipuliert 3 Datensätze. Es sind 1 BEFORE-STATEMENT-, 3 BEFORE-ROW-, 3 AFTER-ROW- und 2 AFTER-STATEMENT-Trigger betroffen. Wie führt SQL/DB2 diese aus?",code:null,opts:["Alle BEFORE-Trigger 'en block' vor allen Datensatzänderungen, alle AFTER-Trigger 'en block' danach","Jeder ROW-Trigger unmittelbar vor/nach seiner einzelnen Datensatzänderung","In zufälliger Reihenfolge","Nur die STATEMENT-Trigger werden ausgeführt"],ans:0,exp:"SQL/DB2: BEFORE-Trigger gesammelt vorher, AFTER-Trigger gesammelt nachher — das umgeht das Mutating-Table-Problem. Oracle führt ROW-Trigger dagegen unmittelbar vor/nach jeder einzelnen Datensatzänderung aus.",source:"VL 9"},
  {cat:"Ausführungsmodelle",q:"Welche Regel gilt bei SQL/DB2 für BEFORE-Trigger?",code:null,opts:["Sie dürfen keine DML-Befehle als Aktionen enthalten","Sie dürfen nur DELETE-Befehle enthalten","Sie feuern nach den AFTER-Triggern","Sie können COMMIT enthalten"],ans:0,exp:"Bei SQL/DB2 sind DML-Befehle in BEFORE-Triggern verboten — das umgeht das Mutating-Table-Problem. Oracle erlaubt BEFORE-Trigger mit DML und handelt sich das Problem dafür ein.",source:"VL 9"},
  {cat:"Triggerfallen",q:"Was steckt hinter dem Mutating-Table-Problem?",code:null,opts:["ROW-Trigger könnten die Tabelle lesen/ändern, die gerade vom auslösenden DML-Befehl geändert wird — das verletzt die Reihenfolgeunabhängigkeit","Die Tabelle wird bei jedem Trigger physisch kopiert","Trigger löschen versehentlich den Index","Statement-Trigger feuern doppelt"],ans:0,exp:"Das Ergebnis von Aktionen soll unabhängig von der Reihenfolge der Datensätze sein. Greift ein ROW-Trigger auf die gerade mutierende Tabelle zu, wäre das Ergebnis reihenfolgeabhängig — Oracle markiert die Tabelle als 'mutating' und wirft einen Fehler.",source:"VL 9"},
  {cat:"Integritätsbedingungen",q:"Welche Trigger werden für die Integritätsprüfung bevorzugt eingesetzt?",code:null,opts:["BEFORE-Trigger (ggf. auch AFTER sinnvoll)","Ausschließlich INSTEAD-OF-Trigger","Nur LOGIN-Trigger","AFTER-Trigger mit COMMIT"],ans:0,exp:"Bevorzugt werden BEFORE-Trigger: Sie können den fehlerauslösenden DML-Befehl zurückrollen oder Werte in den Transitionsvariablen korrigieren, bevor geschrieben wird.",source:"VL 9"},
  {cat:"Trigger-Grundlagen",q:"Wie oft feuert dieser Trigger, wenn ein UPDATE 5 Datensätze ändert, bei denen sich der Bestand tatsächlich ändert?",code:"CREATE TRIGGER Teile_UPDATE\nBEFORE UPDATE OF Bestand ON Lagerbestand\nFOR EACH ROW\nWHEN (NEW.Bestand <> OLD.Bestand)\n...",opts:["1-mal","5-mal","10-mal","Gar nicht"],ans:1,exp:"FOR EACH ROW macht ihn zum ROW-Trigger: Er feuert einmal pro manipuliertem Datensatz, dessen WHEN-Bedingung erfüllt ist — hier also 5-mal.",source:"VL 9"},
];

// ── BLOCK 7: Zugriffspfade & Optimierung (VL 10–11) ──
const DBII_B7 = [
  {cat:"Anfrageoptimierung",q:"Was beschreibt der logische Anfrageplan im Unterschied zum Query Execution Plan (QEP)?",code:null,opts:["Der logische Plan beschreibt WAS berechnet wird (Algebra-Operatoren), der QEP WIE es physisch ausgeführt wird","Der logische Plan enthält die konkreten Joinalgorithmen","Der QEP wird vom Nutzer in SQL geschrieben","Beide sind identisch"],ans:0,exp:"SQL beschreibt das Was. Der logische Plan (Selektion, Projektion, Join, ...) wird umgeschrieben und in einen physischen Query Execution Plan mit konkreten Operator-Implementierungen (z.B. HashJoin, IndexScan) übersetzt.",source:"VL 10"},
  {cat:"Anfrageoptimierung",q:"Welche Heuristiken nutzt die Planumschreibung?",code:null,opts:["Selektionsbedingungen so weit wie möglich zu den Blättern verschieben","Projektionen so weit wie möglich zu den Blättern verschieben","Die Größe der Zwischenresultate minimieren","Joins immer als kartesisches Produkt ausführen"],ans:[0,1,2],exp:"Selektionen und Projektionen werden früh (Richtung Blätter) ausgeführt, um Zwischenergebnisse klein zu halten. Genauere Entscheidungen treffen Kostenmodelle auf Basis von Statistiken.",source:"VL 10"},
  {cat:"Anfrageoptimierung",q:"Worauf basiert die Kostenabschätzung verschiedener Ausführungsvarianten?",code:null,opts:["Auf vordefinierten Kostenmodellen mit Statistiken über die Daten und Selektivitäten","Auf der alphabetischen Reihenfolge der Tabellennamen","Auf der Anzahl der Nutzer","Auf dem Alter der Datenbank"],ans:0,exp:"Der Optimierer schätzt die Kosten eines QEP als Summe der Operatorkosten — mithilfe von Statistiken (Tupelanzahl, Werteverteilungen) und der Selektivität von Bedingungen.",source:"VL 10"},
  {cat:"Index-Grundlagen",q:"Wann ist ein Index-Scan gegenüber einem Table-Scan sinnvoll?",code:null,opts:["Bei geringer Selektivität, d.h. kleiner Resultatmenge (Faustregel: max. ca. 5% der Tupel)","Immer, unabhängig von der Ergebnisgröße","Nur bei Tabellen mit weniger als 5 Seiten","Wenn die gesamte Tabelle zurückgegeben wird"],ans:0,exp:"Index-Scans lohnen sich nur bei kleinen Ergebnismengen (Nutzschwelle ca. 5%). Bei kleinen Tabellen oder großen Resultatmengen ist der sequentielle Table-Scan effizienter (sequentielles Lesen ist deutlich schneller als viele disk seeks).",source:"VL 11"},
  {cat:"Index-Grundlagen",q:"Was unterscheidet einen Primary (Clustered) Index von einem Secondary Index?",code:null,opts:["Der Primary Index bestimmt die physische Speicherreihenfolge; der Secondary Index ist ein alternativer Zugriffspfad","Secondary Indexe sind immer schneller","Primary Indexe existieren nur in NoSQL-Systemen","Es gibt keinen Unterschied"],ans:0,exp:"Beim Clustered Index entspricht die physische Reihenfolge der Tupel der Indexordnung (z.B. via PK). Beim Non-Clustered/Secondary Index unterscheiden sich logische und physische Reihenfolge — Zugriffe streuen über viele Seiten.",source:"VL 11"},
  {cat:"Index-Grundlagen",q:"Warum sind binäre Suchbäume für Externspeicher ungeeignet?",code:null,opts:["Ein Knotenzugriff entspricht einem Plattenzugriff und die Baumhöhe wird sehr groß (z.B. Höhe 23 bei 10⁷ Datensätzen)","Sie können keine Zahlen speichern","Sie erlauben keine Suche","Sie benötigen keinen Speicher"],ans:0,exp:"Bei binären Knoten pro Seite wird die Höhe riesig und jede Ebene kostet einen Plattenzugriff. Lösung: 'fette' Knoten, die eine ganze Seite füllen — Mehrwegbäume wie der B-Baum.",source:"VL 11"},
  {cat:"B-Bäume",q:"Wie viele Einträge enthält jeder Knoten (außer der Wurzel) in einem B-Baum vom Grad k?",code:null,opts:["Mindestens k und höchstens 2·k","Genau k","Höchstens k und mindestens 2·k","Beliebig viele"],ans:0,exp:"Der Füllungsgrad liegt strikt im Intervall [k, 2k]. Das ermöglicht einfaches Aufspalten bei Überlauf und Verschmelzen/Ausgleichen bei Unterlauf.",source:"VL 11"},
  {cat:"B-Bäume",q:"Was passiert bei einem Überlauf (2k+1 Elemente) in einem B-Baum-Knoten?",code:null,opts:["Der Knoten wird in zwei Knoten mit je k Elementen aufgespalten und das mittlere Element wandert in den Vaterknoten","Der Knoten wird gelöscht","Der gesamte Baum wird neu aufgebaut","Das größte Element wird verworfen"],ans:0,exp:"Beim Überlauf: Aufspalten in zwei Knoten mit k Elementen, das mittlere Element steigt in den Vater auf — eventuell wiederholt bis zur Wurzel. Beim Unterlauf: Ausgleichen mit Nachbarn oder Verschmelzen.",source:"VL 11"},
  {cat:"B-Bäume",q:"Was zeichnet B+-Bäume gegenüber B-Bäumen aus?",code:null,opts:["Daten stehen nur in den Blattknoten, was einen größeren Fan-out und damit kleinere Höhe ermöglicht","Daten stehen nur in der Wurzel","Sie sind unbalanciert","Sie erlauben keine Bereichssuchen"],ans:0,exp:"Im B+-Baum enthalten innere Knoten nur Schlüssel (Redundanz), die Daten/TIDs liegen in den Blättern. Ergebnis: größerer Verzweigungsgrad (>100 realistisch), typischerweise reichen 3–4 Ebenen, weniger I/O, einfacheres Löschen.",source:"VL 11"},
  {cat:"B-Bäume",q:"Welche Suchkomplexität hat ein B-Baum mit n Datensätzen und Grad k?",code:null,opts:["O(log_k n)","O(n)","O(n²)","O(1)"],ans:0,exp:"Die Suche verläuft entlang der Höhe des balancierten Mehrwegbaums — logarithmisch zur Basis des Verzweigungsgrads: O(log_k n).",source:"VL 11"},
  {cat:"Spezialindexe",q:"Wofür eignen sich Bitmap-Indexe besonders?",code:null,opts:["Attribute mit wenigen verschiedenen Werten, deren Bedingungen sich per Bit-Operationen (AND/OR) kombinieren lassen","Attribute mit ausschließlich eindeutigen Werten","Volltextsuche in Dokumenten","Speicherung von BLOBs"],ans:0,exp:"Pro Attributwert wird eine Bitliste geführt. Bedingungen lassen sich extrem effizient als Konjunktion/Disjunktion der Bitmaps auswerten — ideal bei geringer Wertevielfalt.",source:"VL 11"},
  {cat:"Spezialindexe",q:"Was ist ein Composite Index?",code:null,opts:["Ein Index (z.B. B+-Baum) über mehrere Attribute gemeinsam","Ein Index, der aus mehreren Datenbanken besteht","Eine Kombination aus Tabelle und View","Ein automatisch erzeugter Statistik-Cache"],ans:0,exp:"Composite Indexe indexieren Attributkombinationen. Function-Based Indexes indexieren dagegen Funktionsergebnisse über Attributen (z.B. UPPER(name)) und können ebenfalls composite sein.",source:"VL 11"},
  {cat:"Anfrageoptimierung",q:"Welche Voraussetzung hat ein Hash Join?",code:null,opts:["Nur Gleichheitsvergleiche — dafür weder Sortierung noch Indexe nötig","Ein Index auf beiden Join-Attributen","Vorsortierte Eingaberelationen","Ein Bitmap-Index"],ans:0,exp:"Der Hash Join baut eine temporäre Hashtabelle über das Join-Attribut auf und braucht weder Sortierung noch Indexe — funktioniert aber nur bei Gleichheits-Joins. Der Index-Join setzt dagegen einen vorhandenen Index voraus.",source:"VL 10"},
];

// ── BLOCK 8: DB Tuning & NoSQL (VL 12) ──
const DBII_B8 = [
  {cat:"Tuning",q:"Welche Aufgaben übernimmt ein Datenbanksystem gegenüber einem reinen Dateisystem?",code:null,opts:["Transaktionen und Synchronisation","Anfragesprache und Anfrageoptimierung","Datenintegrität und Zugriffsschutz","Ausschließlich das Ablegen von Dateien in Ordnern"],ans:[0,1,2],exp:"Ein DBS bietet u.a. Benutzerverwaltung, Zugriffsschutz, Transaktionen, deklarative Anfragesprache mit Optimierung, Datenanalyse, persistente Speicherung, Integrität und ein Datenmodell — weit mehr als ein Dateisystem.",source:"VL 12"},
  {cat:"Tuning",q:"Welche softwareseitigen Tuning-Maßnahmen nennt die Vorlesung?",code:null,opts:["Denormalisierung (kontrollierte Redundanz)","Mehrstufige View-Hierarchien prüfen und auflösen","Partitionierung und materialisierte Sichten","Ausschließlich den Kauf schnellerer Festplatten"],ans:[0,1,2],exp:"Ein Großteil des Tuning-Potentials liegt im SQL-Code und Schema: Denormalisierung, Auflösen tiefer View-Hierarchien, Partitionierung, Clustering und materialisierte Sichten. Hardware-Tuning ist der andere Weg.",source:"VL 12"},
  {cat:"NoSQL-Grundlagen",q:"Wofür steht 'NoSQL' laut Vorlesung am treffendsten?",code:null,opts:["Next Generation Database Systems: nicht-relational, schemalos, verteilt, horizontal skalierbar","Ein striktes Verbot von SQL ('no to SQL')","Ausschließlich 'not only SQL'","Eine neue Version des SQL-Standards"],ans:0,exp:"'No to SQL' ist zu eng, 'not only SQL' passt auch auf Oracle/PostgreSQL. Gemeint sind Next-Generation-Systeme: nicht-relational, schemalos, eventual consistent (BASE), einfache API, verteilt, horizontal skalierbar, meist open-source.",source:"VL 12"},
  {cat:"NoSQL-Grundlagen",q:"Was ersetzt in vielen NoSQL-Systemen das ACID-Prinzip?",code:null,opts:["BASE mit eventual consistency","CRUD","SOLID","REST"],ans:0,exp:"Statt strikter ACID-Transaktionen setzen viele NoSQL-Systeme auf BASE — die Daten werden 'eventual', also irgendwann, konsistent. Das ermöglicht massive Parallelität und horizontale Skalierung.",source:"VL 12"},
  {cat:"NoSQL-Grundlagen",q:"Welche vier NoSQL-Systemkategorien behandelt die Vorlesung hauptsächlich?",code:null,opts:["Key-Value Stores, Document Databases, Column-Family Stores, Graph Databases","Relationale, hierarchische, netzwerkartige und objektorientierte Systeme","In-Memory, On-Disk, Hybrid und Cloud","SQL-92, SQL:1999, SQL:2003 und SQL:2016"],ans:0,exp:"Die Hauptkategorien sind Key-Value Stores, Document Databases, Column-Family Stores und Graph Databases (daneben Stream-DBs, XML-DBS, OODBMS etc.).",source:"VL 12"},
  {cat:"Key-Value & Document",q:"Welche Basisoperationen bietet ein Key-Value Store?",code:null,opts:["get, put und delete — Datenzugriff nur über den Schlüssel","SELECT, JOIN und GROUP BY","MATCH und TRAVERSE","MapReduce-Jobs"],ans:0,exp:"Key-Value Stores sind im Kern Hash-Tabellen: get (abfragen), put (setzen), delete (löschen). Der Zugriff erfolgt ausschließlich über den Schlüssel, die Values sind schemalos.",source:"VL 12"},
  {cat:"Key-Value & Document",q:"Was gibt TTL nach diesem Redis-Befehl ungefähr zurück?",code:"redis> SET foo \"bar\"\nredis> EXPIRE foo 3\nredis> TTL foo",opts:["Die verbleibende Lebenszeit des Schlüssels in Sekunden","Die Anzahl der Zugriffe auf foo","Immer -1","Den Wert 'bar'"],ans:0,exp:"EXPIRE setzt eine Time-To-Live. TTL liefert die Restlaufzeit — danach existiert der Schlüssel nicht mehr (GET liefert nil). Das ergibt cache-ähnliches Verhalten.",source:"VL 12"},
  {cat:"Key-Value & Document",q:"Wofür eignen sich Key-Value Stores wie Redis typischerweise — und wofür nicht?",code:null,opts:["Geeignet: Web Sessions, Nutzerprofile, Warenkorb-Management","Geeignet: schneller Zugriff auf alle Infos mit einem GET/PUT","Ungeeignet: Beziehungen zwischen Daten und komplexe Datenanalyse","Geeignet: Multioperationstransaktionen mit ACID"],ans:[0,1,2],exp:"KV-Stores glänzen bei schnellem schlüsselbasiertem Zugriff (Sessions, Profile, Warenkörbe, Microblogging). Ungeeignet sind sie für verknüpfte Daten, Multioperationstransaktionen und Abfragen über Values.",source:"VL 12"},
  {cat:"Key-Value & Document",q:"Was kennzeichnet Document Databases wie MongoDB?",code:"db.foo.insert({name:\"sue\", age:26,\n  groups:[\"news\",\"sports\"]})",opts:["Werte sind hierarchische Dokumente (z.B. JSON) mit flexiblem Schema, Werteabfragen sind möglich","Es können nur flache Schlüssel-Wert-Paare gespeichert werden","Joins sind der zentrale Anfragemechanismus","Jedes Dokument braucht ein festes relationales Schema"],ans:0,exp:"Dokumente sind Baumstrukturen (JSON/XML) mit Listen, Mengen und eingebetteten Dokumenten. Anders als bei reinen KV-Stores sind Abfragen über die Werte möglich — aber keine Joins, keine ACID-Transaktionen.",source:"VL 12"},
  {cat:"Key-Value & Document",q:"Was liefert diese MongoDB-Abfrage?",code:"db.inventory.find({type:\"food\",\n  price:{$lt:9.95}})",opts:["Alle Dokumente mit type 'food' UND price kleiner als 9,95","Alle Dokumente mit type 'food' ODER price kleiner 9,95","Nur das erste passende Dokument","Einen Fehler, da $lt nicht existiert"],ans:0,exp:"Suchbedingungen im find() wirken als Konjunktion (UND). $lt bedeutet 'less than'. Das Ergebnis ist eine Kollektion von Dokumenten.",source:"VL 12"},
  {cat:"Column & Graph",q:"Was ist die Grundidee von Column-Family Stores wie Cassandra?",code:null,opts:["Spaltenweise Organisation für schnelle Aggregation und Kompression bei flexiblem Schema","Alle Daten in einer einzigen Zeile speichern","Ausschließlich Bilder speichern","Daten nur im RAM halten"],ans:0,exp:"Column-Family Stores organisieren Daten spaltenorientiert mit mehrdimensionalen Schlüsseln — gut für sequentielles Einlesen, Kompression und schnelle Aggregation. Cassandra bietet mit CQL eine SQL-artige Sprache, aber keine Joins.",source:"VL 12"},
  {cat:"Column & Graph",q:"Wie sind Daten in einer Graph Database wie Neo4j organisiert?",code:"create (n1 {Name:'Joe'})\nSTART a=node(1), b=node(2)\nCREATE a-[r:friend {Link:'strong'}]->b",opts:["Als Property-Graph: Knoten mit Eigenschaften und typisierte Kanten mit Eigenschaften","Als Tabellen mit Fremdschlüsseln","Als flache Schlüssel-Wert-Paare","Als unstrukturierte Textdateien"],ans:0,exp:"Im Property-Graph sind Knoten Objektinstanzen mit Eigenschaften, Kanten typisierte Beziehungen mit eigenen Eigenschaften. Anfragesprachen wie Cypher fokussieren auf Pfadausdrücke. Neo4j bietet sogar ACID-Transaktionen.",source:"VL 12"},
  {cat:"Column & Graph",q:"Für welche Anwendungsfälle sind Graph Databases typisch?",code:null,opts:["Soziale Netzwerke und Logistiknetze","Empfehlungsdienste (Recommender Systems)","Standortbezogene Dienste und Routing","OLAP-Reasoning über riesige Teilgraphen"],ans:[0,1,2],exp:"Graph-DBs glänzen beim Traversieren vernetzter Daten: soziale Netzwerke, Lieferketten, Routing, Empfehlungen. Ungeeignet: massenhafte Attributwert-Änderungen und Reasoning über große Teilgraphen (z.B. OLAP).",source:"VL 12"},
];
